  // Close mobile menu on route change
  useEffect(() => {
    setIsMenuOpen(false);
    window.scrollTo(0, 0);
  }, [location]);

  return (
    <div className="min-h-screen flex flex-col font-sans text-stone-800 bg-stone-50">
      {/* Top Bar */}
      <div className="bg-brand-800 text-white py-2 px-4 text-sm hidden md:block">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex gap-4">
            <span className="flex items-center gap-2"><Phone size={14} /> {CONTACT_INFO.phone}</span>
            <span className="flex items-center gap-2 text-brand-200">Mo–Fr: 10:00 – 18:00</span>
          </div>
          <div className="flex gap-4">
             <a href={`https://wa.me/${CONTACT_INFO.phone.replace(/\s/g, '')}`} target="_blank" rel="noopener noreferrer" className="hover:text-brand-300 transition-colors flex items-center gap-1">
               <MessageCircle size={14} /> WhatsApp
             </a>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <nav 
        className={`sticky top-0 z-50 transition-all duration-300 ${
          scrolled ? 'bg-white shadow-md py-2' : 'bg-white/90 backdrop-blur-md py-4'
