          </NavLink>

          {/* Desktop Menu */}
          <div className="hidden md:flex gap-8 items-center">
            {NAV_ITEMS.map((item) => (
              <NavLink
                key={item.path}
                to={item.path}
                className={({ isActive }) =>
                  `text-sm uppercase tracking-wider font-semibold transition-colors duration-200 ${
                    isActive ? 'text-brand-600 border-b-2 border-brand-500' : 'text-stone-600 hover:text-brand-600'
                  }`
                }
              >
