import React, { useState } from 'react';
import Section from '../components/Section';
import { FAQS } from '../constants';
import { ChevronDown, ChevronUp } from 'lucide-react';

const FAQ: React.FC = () => {
  const [openIndex, setOpenIndex] = useState<number | null>(0);

  const toggle = (index: number) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  return (
    <>
      <div className="bg-brand-50 py-16">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <h1 className="text-4xl font-display font-bold text-brand-800 mb-4">Häufige Fragen</h1>
          <p className="text-stone-600">Alles Wichtige zu Ihrer Behandlung.</p>
        </div>
      </div>

      <Section>
        <div className="max-w-3xl mx-auto">
          {FAQS.map((faq, index) => (
            <div key={index} className="mb-4">
              <button
                onClick={() => toggle(index)}
                className={`w-full text-left px-6 py-4 rounded-xl flex justify-between items-center transition-all duration-200 ${
                  openIndex === index 
                    ? 'bg-brand-600 text-white shadow-md' 
                    : 'bg-white hover:bg-stone-50 text-stone-800 shadow-sm border border-stone-100'
                }`}
              >
                <span className="font-bold">{faq.question}</span>
                {openIndex === index ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
              </button>
              <div 
                className={`overflow-hidden transition-all duration-300 ease-in-out ${
                  openIndex === index ? 'max-h-40 opacity-100 mt-2' : 'max-h-0 opacity-0'
                }`}
              >
                <div className="px-6 py-4 text-stone-600 bg-white rounded-xl border border-stone-100">
                  {faq.answer}
                </div>
              </div>
            </div>
          ))}
        </div>
      </Section>
    </>
  );
};

export default FAQ;

