        <div className="max-w-7xl mx-auto px-4 text-center">
          <h1 className="text-4xl font-display font-bold text-brand-900 mb-4">Preisliste</h1>
          <p className="text-stone-600 max-w-2xl mx-auto">
            Transparent und fair.
          </p>
        </div>
      </div>

      <Section>
        <div className="grid lg:grid-cols-2 gap-8 max-w-6xl mx-auto">
          {PRICES.map((category, idx) => (
            <div key={idx} className="bg-white rounded-2xl shadow-sm border border-brand-100 overflow-hidden flex flex-col hover:shadow-md transition-shadow duration-300">
              <div className="bg-brand-300/30 p-6 border-b border-brand-200 flex items-center gap-4">
                {category.icon && (
                  <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-accent-600 shadow-sm shrink-0">
                    <category.icon size={24} />
                  </div>
                )}
                <h2 className="text-xl font-bold text-brand-900">{category.title}</h2>
              </div>
              <div className="p-6">
                <ul className="space-y-4">
                  {category.items.map((item, itemIdx) => (
                    <li key={itemIdx} className="flex justify-between items-end border-b border-stone-100 pb-2 last:border-0 last:pb-0">
                      <span className="font-medium text-stone-700">{item.name}</span>
                      <span className="font-bold text-brand-900 whitespace-nowrap ml-4">{item.price}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-16 text-center">
          <p className="text-stone-500 mb-6 max-w-2xl mx-auto text-sm">
            * Alle Preise inkl. MwSt. Preise können je nach Aufwand leicht variieren. 
            Bitte informieren Sie uns bei der Terminvereinbarung über spezielle Anforderungen.
          </p>
          <a 
            href={BOOKING_URL}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-block bg-brand-900 hover:bg-brand-800 text-white px-8 py-3 rounded-full font-semibold transition-colors shadow-md"
          >
            Termin vereinbaren
          </a>
        </div>
      </Section>
    </>
  );
};

export default Prices;
